# DE 1701.  Hannover Hbf - Seelze Rbf
#
let hh = path("d3.de.h.1700");

with detail = 4,
     railway = :first :double :cat:ac15 :nopax
{
    with link = "point.de.Hannover-Kurve", railway = :station {
        track(hh[:kur - 1dl, :kur + 0.5seg] << 2mo);
        track(:single,
                hh[:kur - 0.1dl, :kur] << 2.5mo
            --  hh[:kur + 1dl, :kur + 1.1dl] << 3.5mo
        );
        marker(:left :de.abzw,
            hh[:kur - 1dl] << 2.5mo << 0.5mt,
            hh[:kur - 1dl] << 1.5mo >> 0.5mt
        );
        station(:top, hh[:kur - 1dl] >> 2.5mo >> 0.5mt + (0dt, -1dt),
            hbox(:center:base :small, "H. ", span(:bold, "Kurve")),
            hbox(:center:top,
                vbox(:right:top, "1701: ", "1704: "),
                vbox(:sep:top,
                    hbox(:sep:base, "6,", anchor(), "228"),
                    hbox(:sep:base, "1,", anchor(), "01")
                )
            )
        );
    }

    with link = "line.de.1701" {
        track(:ror, hh[:kur + 0.5seg, :lea] << 2mo);
    }

    # point.de.Letter-Abzw  de.1700

    with link = "line.de.1701" {
        with layer = -1 track(:lor:ror,
                hh[:lea.yr - 2.01mo, :lea.yr + 2mo] << 2mo
            ..  hh[:let.yl, :let.yl + 0.1dl] << 3.5mo
        );
    }

    # point.de.Seelze-Ost  de.1750
    # point.de.Seelze-Rbf  de.1750
}

